from flask import Flask, jsonify
from bson.objectid import ObjectId
from pymongo import MongoClient

app = Flask(__name__)

# Connect to MongoDB
client = MongoClient('localhost', 27017)
db = client['mydatabase']

# User profile storage
@app.route('/users', methods=['POST'])
def create_user():
    data = request.get_json()
    user = {
        'name': data['name'],
        'email': data['email']
    }
    db.users.insert_one(user)
    return jsonify({'message': f'User {data["name"]} created successfully!'}), 201

# Document queries
@app.route('/documents', methods=['GET'])
def get_all_documents():
    documents = db.documents.find()
    return jsonify([doc for doc in documents])

# Aggregation pipelines
@app.route('/aggregate', methods=['POST'])
def aggregate():
    data = request.get_json()
    pipeline = [{'$match': {'name': 'John'}}, {'$sort': {'age': 1}}]
    result = db.documents.aggregate(pipeline)
    return jsonify([doc for doc in result])